import SplitType from "split-type";

gsap.registerPlugin(useGSAP, ScrollTrigger);

const AnimatedH1 = ({
  children,
  className = "",
  delay = 0,
  duration = 1,
  ease = "power4.out",
  stagger = 0.1,
  lineSelector = "",
  animateOnScroll = false,
  direction = "bottom",
