const Transition = (OgPage) => {
  return function WithTransition(props) {
    return (
      <>
        <OgPage {...props} />
        <motion.div
          className="slide-in"
          initial={{ scaleY: 0 }}
          animate={{ scaleY: 0 }}
          exit={{ scaleY: 1 }}
          transition={{ duration: 0.75, ease: [0.83, 0, 0.17, 1] }}
        />
        <motion.div
