          initial={{ scaleY: 1 }}
          animate={{ scaleY: 0 }}
          exit={{ scaleY: 0 }}
          transition={{ duration: 0.75, ease: [0.83, 0, 0.17, 1] }}
        />
      </>
    );
  };
};

