        duration: 1,
        stagger: 0.1,
        ease: "power4.out",
        scrollTrigger: {
          trigger: ".stats",
          start: "top 50%",
          toggleActions: "play none none none",
        },
      }
    );
    scrollTriggerInstances.push(statsAnimation.scrollTrigger);

    if (window.innerWidth > 1000) {
      const portraitAnimation = gsap.to(".about-hero-portrait", {
        y: -200,
