        scrollTrigger: {
          trigger: ".about-hero",
          start: "top top",
          end: "bottom top",
          scrub: 1,
        },
      });
      scrollTriggerInstances.push(portraitAnimation.scrollTrigger);

      const tag1Animation = gsap.to("#tag-1", {
