          trigger: ".about-copy",
          start: "top bottom",
          end: "bottom+=100% top",
          scrub: 1,
        },
      });
      scrollTriggerInstances.push(tag1Animation.scrollTrigger);

      const tag2Animation = gsap.to("#tag-2", {
        y: -150,
        rotation: 70,
        scrollTrigger: {
          trigger: ".about-copy",
          start: "top bottom",
          end: "bottom+=100% top",
          scrub: 1,
        },
      });
      scrollTriggerInstances.push(tag2Animation.scrollTrigger);

      const tag3Animation = gsap.to("#tag-3", {
        y: -400,
        rotation: 120,
        scrollTrigger: {
          trigger: ".about-copy",
          start: "top bottom",
          end: "bottom+=100% top",
          scrub: 1,
        },
      });
      scrollTriggerInstances.push(tag3Animation.scrollTrigger);

      const tag4Animation = gsap.to("#tag-4", {
        y: -350,
        rotation: -60,
        scrollTrigger: {
          trigger: ".about-copy",
          start: "top bottom",
          end: "bottom+=100% top",
          scrub: 1,
        },
      });
      scrollTriggerInstances.push(tag4Animation.scrollTrigger);

      const tag5Animation = gsap.to("#tag-5", {
        y: -200,
        rotation: 100,
        scrollTrigger: {
